146→    public static void updateAnalyticsPreference(Context ctx,
147→                                                 Dispatcher mDispatcher,
148→                                                 AccountStore mAccountStore,
149→                                                 boolean optOut) {
150→        AnalyticsTracker.setHasUserOptedOut(optOut);
151→        if (optOut) {
152→            AnalyticsTracker.clearAllData();
153→        }
154→        // Sync with wpcom if a token is available
155→        if (mAccountStore.hasAccessToken()) {
156→            mAccountStore.getAccount().setTracksOptOut(optOut);
157→            PushAccountSettingsPayload payload = new PushAccountSettingsPayload();
158→            payload.params = new HashMap<>();
159→            payload.params.put("tracks_opt_out", optOut);
160→            mDispatcher.dispatch(AccountActionBuilder.newPushSettingsAction(payload));
161→        }
162→        // Store the preference locally
163→        SharedPreferences prefs = PreferenceManager.getDefaultSharedPreferences(ctx);
164→        final SharedPreferences.Editor editor = prefs.edit();
165→        editor.putBoolean(ctx.getString(R.string.pref_key_send_usage), !optOut);
166→        editor.apply();
