102→    public static void trackEditorCreatedPost(String action, Intent intent, SiteModel site, PostImmutableModel post) {
103→        Map<String, Object> properties = new HashMap<>();
104→        // Post created from the post list (new post button).
105→        String normalizedSourceName = "post-list";
106→
107→        if (Intent.ACTION_SEND.equals(action) || Intent.ACTION_SEND_MULTIPLE.equals(action)) {
108→            // Post created with share with WordPress
109→            normalizedSourceName = "shared-from-external-app";
110→        }
111→        if (EditPostActivity.NEW_MEDIA_POST.equals(
112→                action)) {
113→            // Post created from the media library
114→            normalizedSourceName = "media-library";
115→        }
116→        if (intent != null && intent.hasExtra(EXTRA_IS_QUICKPRESS)) {
117→            // Quick press
118→            normalizedSourceName = "quick-press";
119→        }
120→        PostUtils.addPostTypeAndPostFormatToAnalyticsProperties(post, properties);
121→        properties.put("created_post_source", normalizedSourceName);
122→
123→        if (intent != null
124→            && intent.hasExtra(EXTRA_CREATION_SOURCE_DETAIL)
125→            && normalizedSourceName == "post-list") {
126→            PagePostCreationSourcesDetail source =
127→                    (PagePostCreationSourcesDetail) intent.getSerializableExtra(EXTRA_CREATION_SOURCE_DETAIL);
128→            properties.put(
129→                    CREATED_POST_SOURCE_DETAIL_KEY,
130→                    source != null ? source.getLabel() : PagePostCreationSourcesDetail.NO_DETAIL.getLabel()
131→            );
132→        } else {
133→            properties.put(
134→                    CREATED_POST_SOURCE_DETAIL_KEY,
135→                    PagePostCreationSourcesDetail.NO_DETAIL.getLabel()
136→            );
137→        }
138→
